<template>

  <section class="guest-book">

    <!-- 🔥 2개만 표시 -->
    <div class="message-list">
      <div
        v-for="post in posts.slice(0,2)"
        :key="post.id"
        class="message-card"
      >
        <p class="writer">{{ post.name }}</p>
        <p class="content">{{ post.message }}</p>
      </div>
    </div>

    <!-- 전체 리스트 모달 -->
    <div v-if="openListModal" class="modal-overlay" @click.self="openListModal = false">
      <div class="modal-box large">
        <h5>전체 방명록</h5>
        <p class="guestbook-answer">
          행복하게 잘살겠습니다 ♥︎  감사합니다.<br>

          혜분 우섭 올림 👰🏻‍♀️🤵🏻
        </p>

        <div class="scroll-box">
          <div
            v-for="post in posts"
            :key="post.id"
            class="message-card"
          >
            <p class="writer">{{ post.name }}</p>
            <p class="content">{{ post.message }}</p>
          </div>
        </div>

        <button class="submit-btn" @click="openListModal = false">
          닫기
        </button>
      </div>
    </div>

    <!-- 모달 -->
    <div v-if="openModal" class="modal-overlay" @click.self="closeModal">
      <div class="modal-box">
        <h3>축하 메시지 남기기</h3>

        <input
          v-model="name"
          type="text"
          placeholder="이름"
        />

        <textarea
          v-model="message"
          rows="4"
          placeholder="메시지를 입력해주세요"
        />

        <div class="modal-buttons">
          <button class="cancel-btn" @click="closeModal">취소</button>
          <button class="submit-btn" @click="submitPost">전송</button>
        </div>
      </div>
    </div>

    <!-- 더보기 버튼 -->
    <button
      v-if="posts.length > 2"
      class="more-btn"
      @click="openListModal = true"
    >
      전체보기
    </button>

    <!-- 글쓰기 버튼 -->
    <button class="write-btn" @click="openModal = true">
      <img :src="require('@/assets/icon/write.png')" alt="write" />
    </button>

  </section>
</template>

<script>
import { ref, onMounted } from 'vue'
import { db } from '@/store/firebase'
import {
  collection,
  addDoc,
  query,
  orderBy,
  onSnapshot
} from 'firebase/firestore'

export default {
  name: 'WeddingGuestBook',
  setup () {
    const name = ref('')
    const message = ref('')
    const posts = ref([])
    const openModal = ref(false)
    const openListModal = ref(false)

    const closeModal = () => {
      openModal.value = false
      name.value = ''
      message.value = ''
    }

    const submitPost = async () => {
      if (!name.value || !message.value) {
        alert('이름과 메시지를 입력해주세요.')
        return
      }

      await addDoc(collection(db, 'guestBook'), {
        name: name.value,
        message: message.value,
        createdAt: new Date()
      })

      closeModal()
    }

    onMounted(() => {
      const q = query(
        collection(db, 'guestBook'),
        orderBy('createdAt', 'desc')
      )

      // 🔥 실시간 반영
      onSnapshot(q, (snapshot) => {
        posts.value = snapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data()
        }))
      })
    })

    return {
      name,
      message,
      posts,
      openModal,
      openListModal,
      closeModal,
      submitPost
    }
  }
}
</script>

